const lts = "0123456789abcdef"
const rnd_i = (range = 16) => {
  return Math.floor(Math.random() * range)
}
const getRandomColor = () => {
  return `#${lts[rnd_i()]}${lts[rnd_i()]}${lts[rnd_i()]}`
}

const LogoStyle = ({ width, height, speed, size, outline, paused }) => {
  return (
    <style>
      {`
.ud{
  animation-duration: ${height / speed ** 2}s;
  ${outline ? "outline: solid blue;" : ""}
  ${paused ? "animation-play-state: paused;" : ""}
}
.lr {
  animation-duration: ${width / speed ** 2}s;
  ${outline ? "outline: solid red;" : ""}
  ${paused ? "animation-play-state: paused;" : ""}
}
.lr > div > span{
  color: black;
}
.lr > div {
  font-size: ${size}rem;
}
`}
    </style>
  )
}

const LogoColorStyle = ({ color }) => {
  return (
    <style id="logo-color">
      {`
.ud{
  color: ${color};
}
.lr > div > span{
  background-color: ${color};
}
`}
    </style>
  )
}

const changeColor = e => {
  const logoColor = document.getElementById("logo-color")
  let color = getRandomColor()
  logoColor.innerHTML = `
.ud{
color: ${color};
}
.lr > div > span{
background-color: ${color};
}
`
}

const DVD = () => {
  const [width, setWidth] = useState(1280)
  const [height, setHeight] = useState(960)
  const [color] = useState("#ffffff")

  const [speed, setSpeed] = useState(15)
  const [size, setSize] = useState(8)
  const [outline, setOutline] = useState(false)
  const [paused, setPaused] = useState(false)
  const [showPanel, setShowPanel] = useState(true)
  const [count, setCount] = useState(0)
  const [hit, setHit] = useState(0)
  const [showStatus, setShowStatus] = useState(false)

  const parameters = {
    width,
    height,
    color,
    speed,
    size,
    outline,
    paused,
  }
  const container_id = "dvd-logo-container"
  const bouncer_id = "bouncer"
  const clearCount = e => {
    setCount(0)
    setHit(0)
  }

  useEffect(() => {
    let timer = null
    const handleBounce = e => {
      changeColor()
      setCount(preCount => preCount + 1)
      let now = performance.now()
      const cost = now - timer || 0
      if (cost < 50) {
        setHit(preCount => preCount + 1)
      }
      timer = now
    }
    // Resize Event Obs
    const container = document.getElementById(container_id)
    const observerOptions = {
      box: "border-box",
    }
    const ob_callback = mut_list => {
      mut_list.forEach(mut => {
        if (mut.target.id === container_id) {
          setWidth(mut.contentRect.width)
          setHeight(mut.contentRect.height)
        }
      })
    }
    const observer = new ResizeObserver(ob_callback)
    observer.observe(container, observerOptions)

    // Border touch Event
    const bouncer = document.getElementById(bouncer_id)
    bouncer.addEventListener("animationiteration", handleBounce)

    // Clean Up
    return () => {
      bouncer.removeEventListener("animationiteration", handleBounce)
      observer.disconnect()
      // Might trigger garbage collect?
    }
  }, [])

  return (
    <div
      style={{
        position: "relative",
        display: "block",
        width: "100vw",
        height: "100vh",
        background: "black",
        overflow: "hidden",
      }}
      id={container_id}
    >
      <Helmet>
        <style>{scssData}</style>
      </Helmet>
      <Seo {...siteData.SEO} />
      {/* Bouncer Element */}
      <div className="ud" id={bouncer_id}>
        <div className="lr">
          <LogoColorStyle color={color} />
          <LogoStyle {...parameters} />
          <DVDLogo />
        </div>
      </div>
      {/* Control Panel */}
      <div className={`control-panel${!showPanel ? " hidden" : ""}`}>
        <div className="control-header">
          <span>Setting</span>
          <IconButton
            aria-label="show control"
            onClick={e => setShowPanel(!showPanel)}
            size="large"
          >
            {showPanel ? (
              <Visibility fontSize="small" />
            ) : (
              <VisibilityOff fontSize="small" />
            )}
          </IconButton>
        </div>
        <form className="control-form" noValidate autoComplete="off">
          <Typography gutterBottom>Logo Size</Typography>
          <Slider
            value={size}
            onChange={(e, v) => setSize(Number(v))}
            aria-labelledby="size-slider"
            min={3}
            step={0.1}
            max={30}
          />
          <Typography gutterBottom>Speed</Typography>
          <Slider
            value={speed}
            onChange={(e, v) => setSpeed(Number(v))}
            aria-labelledby="speed-slider"
            min={1}
            step={1}
            max={50}
          />
          <FormControlLabel
            control={
              <Switch
                checked={outline}
                onChange={e => {
                  setOutline(!outline)
                }}
                name="outline"
                color="primary"
              />
            }
            label="Outline"
          />
          <FormControlLabel
            control={
              <Switch
                checked={!paused}
                onChange={e => {
                  setPaused(!paused)
                }}
                name="Play"
                color="primary"
              />
            }
            label="Play"
          />
          <FormControlLabel
            control={
              <Switch
                checked={showStatus}
                onChange={e => {
                  setShowStatus(!showStatus)
                }}
                name="Status"
                color="primary"
              />
            }
            label="Status"
          />
          <IconButton
            aria-label="Clear Status"
            onClick={clearCount}
            size="large"
          >
            <RefreshIcon fontSize="small" />
          </IconButton>
        </form>
      </div>
      {/* Counter */}
      <Slide direction="up" in={showStatus} mountOnEnter unmountOnExit appear>
        <div className="counter">
          <dl>
            <dt>Bounce</dt>
            <dd>{count}</dd>
            <dt>Hit Corner</dt>
            <dd>{hit}</dd>
          </dl>
        </div>
      </Slide>
    </div>
  )
}

export default DVD
